/**
 * Generate Mathpix firewall config.
 *
 * Data source: https://docs.mathpix.com
 *
 * Mathpix authenticates with two request headers:
 *   - `app_id`  → MATHPIX_APP_ID (stored as a variable, not a secret)
 *   - `app_key` → MATHPIX_APP_KEY (secret)
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.mathpix.com";
// Format: 32 hex chars
const PLACEHOLDER_VALUE = "c0ffeesafelocal5afe10ca1c0ffeesa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Mathpix API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:mathpix",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const mathpixFirewall = {",
    '  name: "mathpix",',
    '  description: "Mathpix OCR API",',
    "  placeholders: {",
    `    MATHPIX_APP_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.mathpix.com",',
    "      auth: {",
    "        headers: {",
    '          app_id: "${{ vars.MATHPIX_APP_ID }}",',
    '          app_key: "${{ secrets.MATHPIX_APP_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Mathpix firewall config...");
  const ts = generateTypeScript();
  writeOutput("mathpix", ts, import.meta.dirname);
}
